func newWorkflowSubscriberLookupCmd(flags *rootFlags) *cobra.Command {
	var email string
	var id string
	var emailSentAfter string
	var emailSentBefore string

	cmd := &cobra.Command{
		Use:   "subscriber-lookup",
		Short: "Fetch one subscriber with tags, custom fields, attribution, and email stats",
		Long: `Looks up a subscriber by email address or Kit subscriber id and returns a
single compact read-only dossier: subscriber profile, custom fields, tags, and
email engagement stats. Use this before support replies, segmentation checks, or
personalization debugging instead of separately calling subscriber, tags, and
stats endpoints.`,
		Example: `  kit-pp-cli workflow subscriber-lookup --email reader@example.com --agent
  kit-pp-cli workflow subscriber-lookup --id 123456 --email-sent-after 2026-01-01 --json`,
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			email = strings.TrimSpace(email)
			id = strings.TrimSpace(id)
			if email == "" && id == "" {
				return usageErr(fmt.Errorf("one of --email or --id is required"))
			}
			if email != "" {
				if _, err := mail.ParseAddress(email); err != nil {
					return usageErr(fmt.Errorf("invalid --email: %w", err))
				}
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}
			c.NoCache = true

			warnings := []string{}
			var subscriber map[string]any
			matches := []map[string]any{}
			if id != "" {
				raw, err := c.Get("/v4/subscribers/"+id, nil)
				if err != nil {
					return classifyAPIError(err, flags)
				}
				subscriber = firstObject(raw, "subscriber", "data")
			} else {
				raw, err := c.Get("/v4/subscribers", map[string]string{
					"email_address":       email,
					"include":             "tags,location,attribution",
					"include_total_count": "true",
					"per_page":            "5",
					"status":              "all",
				})
				if err != nil {
					return classifyAPIError(err, flags)
				}
				matches = firstArray(raw, "subscribers", "data")
				if len(matches) == 0 {
					return notFoundErr(fmt.Errorf("subscriber not found for email %q", email))
				}
				subscriber = matches[0]
				if value, ok := anyIntString(subscriber["id"]); ok {
					id = value
				}
			}

			if id == "" {
				if value, ok := anyIntString(subscriber["id"]); ok {
					id = value
				}
			}
			if id == "" {
				return apiErr(fmt.Errorf("subscriber response did not include an id"))
			}

			out := map[string]any{
				"generated_at": time.Now().UTC().Format(time.RFC3339),
				"subscriber":   subscriber,
				"warnings":     warnings,
			}
			if len(matches) > 1 {
				out["matched_subscribers"] = selectObjectListFields(matches, "id", "email_address", "state", "created_at")
			}

			if raw, err := c.Get("/v4/subscribers/"+id+"/tags", listParams(50)); err != nil {
				warnings = append(warnings, fmt.Sprintf("subscriber tags: %v", err))
			} else {
				tags := firstArray(raw, "tags", "data")
				out["tags"] = selectObjectListFields(tags, "id", "name", "tagged_at")
				out["tag_count"] = totalCount(raw, len(tags))
			}

			statParams := map[string]string{}
			if emailSentAfter != "" {
				statParams["email_sent_after"] = emailSentAfter
			}
			if emailSentBefore != "" {
				statParams["email_sent_before"] = emailSentBefore
			}
			if raw, err := c.Get("/v4/subscribers/"+id+"/stats", statParams); err != nil {
				warnings = append(warnings, fmt.Sprintf("subscriber stats: %v", err))
			} else {
				out["email_stats"] = firstObject(raw, "subscriber", "data")
			}

			out["warnings"] = warnings
			return printJSONFiltered(cmd.OutOrStdout(), out, flags)
		},
	}

	cmd.Flags().StringVar(&email, "email", "", "Subscriber email address to look up")
	cmd.Flags().StringVar(&id, "id", "", "Kit subscriber id to look up")
	cmd.Flags().StringVar(&emailSentAfter, "email-sent-after", "", "Only include subscriber email stats after this YYYY-MM-DD date")
	cmd.Flags().StringVar(&emailSentBefore, "email-sent-before", "", "Only include subscriber email stats before this YYYY-MM-DD date")

	return cmd
}

func clampWorkflowLimit(value, minValue, maxValue int) int {
	if value < minValue {
		return minValue
	}
	if value > maxValue {
		return maxValue
	}
	return value
}

func listParams(sampleSize int) map[string]string {
	return map[string]string{
		"include_total_count": "true",
		"per_page":            fmt.Sprintf("%d", sampleSize),
	}
}

func getWorkflowCollection(c *client.Client, counts map[string]any, warnings *[]string, name, path string, params map[string]string, arrayKey string) []map[string]any {
	raw, err := c.Get(path, params)
	if err != nil {
		*warnings = append(*warnings, fmt.Sprintf("%s: %v", name, err))
		return nil
	}
	items := firstArray(raw, arrayKey, "data")
	counts[name] = totalCount(raw, len(items))
	return items
}

func addListSnapshot(c *client.Client, counts map[string]any, samples map[string]any, warnings *[]string, name, path string, params map[string]string, arrayKey string, sampleFields []string) {
	items := getWorkflowCollection(c, counts, warnings, name, path, params, arrayKey)
	if len(sampleFields) > 0 && len(items) > 0 {
		samples[name] = selectObjectListFields(items, sampleFields...)
	}
}

func totalCount(raw json.RawMessage, fallback int) int {
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return fallback
	}
	if n, ok := numberField(obj, "total_count"); ok {
		return n
	}
	if pagination, ok := obj["pagination"].(map[string]any); ok {
		if n, ok := numberField(pagination, "total_count"); ok {
			return n
		}
	}
	if meta, ok := obj["meta"].(map[string]any); ok {
		if n, ok := numberField(meta, "total_count"); ok {
			return n
		}
	}
	return fallback
}

func numberField(obj map[string]any, key string) (int, bool) {
	v, ok := obj[key]
	if !ok {
		return 0, false
	}
	switch n := v.(type) {
	case float64:
		return int(n), true
	case int:
		return n, true
	default:
		return 0, false
	}
}

func intField(obj map[string]any, key string) int {
	switch v := obj[key].(type) {
	case int:
		return v
	case float64:
		return int(v)
	default:
		return 0
	}
}

func anyIntString(value any) (string, bool) {
	switch v := value.(type) {
	case int:
		return fmt.Sprintf("%d", v), true
	case int64:
		return fmt.Sprintf("%d", v), true
	case float64:
		return fmt.Sprintf("%.0f", v), true
	case json.Number:
		return v.String(), true
	case string:
		if strings.TrimSpace(v) == "" {
			return "", false
		}
		return v, true
	default:
		return "", false
	}
}

func firstObject(raw json.RawMessage, keys ...string) map[string]any {
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return map[string]any{}
	}
	for _, key := range keys {
		if nested, ok := obj[key].(map[string]any); ok {
			return nested
		}
	}
	return obj
}

func firstArray(raw json.RawMessage, keys ...string) []map[string]any {
	var arr []map[string]any
	if err := json.Unmarshal(raw, &arr); err == nil {
		return arr
	}
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return nil
	}
	for _, key := range keys {
		if nested, ok := obj[key].([]any); ok {
			return mapArray(nested)
		}
	}
	for _, key := range sortedKeys(obj) {
		if nested, ok := obj[key].([]any); ok {
			return mapArray(nested)
		}
	}
	return nil
}

func mapArray(values []any) []map[string]any {
	items := make([]map[string]any, 0, len(values))
	for _, value := range values {
		if item, ok := value.(map[string]any); ok {
			items = append(items, item)
		}
	}
	return items
}

func sortedKeys(obj map[string]any) []string {
	keys := make([]string, 0, len(obj))
	for key := range obj {
		keys = append(keys, key)
	}
	sort.Strings(keys)
	return keys
}

func selectObjectListFields(items []map[string]any, fields ...string) []map[string]any {
	out := make([]map[string]any, 0, len(items))
	for _, item := range items {
		out = append(out, selectObjectFields(item, fields...))
	}
	return out
}

func selectObjectFields(item map[string]any, fields ...string) map[string]any {
	out := map[string]any{}
	for _, field := range fields {
		if value, ok := item[field]; ok {
			out[field] = value
		}
	}
	return out
}

func newWorkflowArchiveCmd(flags *rootFlags) *cobra.Command {
	var dbPath string
	var full bool

	cmd := &cobra.Command{
		Use:   "archive",
		Short: "Sync all resources to local store for offline access and search",
		Long: `Archive fetches all syncable resources from the API and stores them in a
local SQLite database. Supports incremental sync (only new data since last run)
and full resync. After archiving, use 'search' for instant full-text search.`,
		Example: `  # Archive all resources
  kit-pp-cli workflow archive

  # Full re-archive (ignore previous sync state)
  kit-pp-cli workflow archive --full`,
		RunE: func(cmd *cobra.Command, args []string) error {
			c, err := flags.newClient()
			if err != nil {
				return err
			}
			c.NoCache = true

			if dbPath == "" {
				dbPath = defaultDBPath("kit-pp-cli")
			}
			s, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer s.Close()

			resources := []string{"account", "account-colors", "account-creator-profile", "account-email-stats", "account-growth-stats", "broadcasts", "broadcasts-stats", "custom-fields", "email-templates", "forms", "posts", "purchases", "segments", "sequences", "snippets", "subscribers", "tags", "webhooks"}
			totalSynced := 0

			// --full clears the cursor here because syncResource reads
			// existingCursor unconditionally; its full param only gates the
			// since filter, not cursor reset. Mirrors newSyncCmd's pattern.
			if full {
				for _, resource := range resources {
					_ = s.SaveSyncState(resource, "", 0)
				}
			}

			for _, resource := range resources {
				res := syncResource(c, s, resource, "", full, 100, false, nil)
				if res.Err != nil {
					fmt.Fprintf(cmd.ErrOrStderr(), "  %s: error: %v\n", resource, res.Err)
					continue
				}
				if res.Warn != nil {
					fmt.Fprintf(cmd.ErrOrStderr(), "  %s: warning: %v\n", resource, res.Warn)
					continue
				}
				totalSynced += res.Count
				fmt.Fprintf(cmd.ErrOrStderr(), "  %s: %d synced\n", resource, res.Count)
			}

			if flags.asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(map[string]any{
					"resources_synced": len(resources),
					"total_items":      totalSynced,
					"store_path":       dbPath,
					"timestamp":        time.Now().UTC().Format(time.RFC3339),
				})
			}

			fmt.Fprintf(cmd.OutOrStdout(), "Archived %d items across %d resources to %s\n", totalSynced, len(resources), dbPath)
			return nil
		},
	}

	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: ~/.local/share/kit-pp-cli/data.db)")
	cmd.Flags().BoolVar(&full, "full", false, "Full re-archive (ignore previous sync state)")

	return cmd
}

func newWorkflowStatusCmd(flags *rootFlags) *cobra.Command {
	var dbPath string

	cmd := &cobra.Command{
		Use:         "status",
		Short:       "Show local archive status and sync state for all resources",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: `  # Show archive status
  kit-pp-cli workflow status

  # Show status as JSON
  kit-pp-cli workflow status --json`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if dbPath == "" {
				dbPath = defaultDBPath("kit-pp-cli")
			}
			s, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer s.Close()

			status, err := s.Status()
			if err != nil {
				return err
			}

			if flags.asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(status)
			}

			if len(status) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No archived data. Run 'workflow archive' to sync.")
				return nil
			}

			fmt.Fprintln(cmd.OutOrStdout(), "Archive Status:")
			total := 0
			for resource, count := range status {
				fmt.Fprintf(cmd.OutOrStdout(), "  %-30s %d items\n", resource, count)
				total += count
			}
			fmt.Fprintf(cmd.OutOrStdout(), "\n  Total: %d items\n", total)
			fmt.Fprintf(cmd.OutOrStdout(), "  Store: %s\n", dbPath)
			return nil
		},
	}

	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")

	return cmd
}

// defaultDBPath is defined in helpers.go
